function getCasierStatus(){
  if(!user)return 'none';
  if(user.casier_verifie===true||user.casier_verifie==='true')return 'verified';
  if(user.casier_uploaded===true||user.casier_uploaded==='true')return 'pending';
  return 'none';
}

