// ── GoodNotes-style whiteboard ──
function _buildBoardInner(){
  var NAV='#2c4f8a';
  var ib='background:none;border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;-webkit-tap-highlight-color:transparent;touch-action:manipulation;font-family:inherit;color:rgba(255,255,255,.85);flex-shrink:0;';
  var glassBtn='background:none;border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;-webkit-tap-highlight-color:transparent;touch-action:manipulation;color:rgba(255,255,255,.9);width:36px;height:36px;border-radius:50%;flex-shrink:0;transition:background .15s;';
  var glassSep='width:1px;height:20px;background:rgba(255,255,255,.18);flex-shrink:0;';
  return ''
    // Top nav bar (dark blue, GoodNotes style)
    // Outer wrapper: full dark blue background including status bar area
    +'<div style="background:'+NAV+';flex-shrink:0;">'
    // Safe-area spacer: always at least 20px so status bar is never hidden
    +'<div style="height:max(env(safe-area-inset-top,20px),20px);"></div>'
    // Actual nav content row (fixed 46px) — sans bouton retour pour plus d'espace aux onglets
    +'<div style="display:flex;align-items:stretch;height:46px;padding:0 6px;">'
    // Bouton maison : retour au visio
    +'<button onclick="_vCloseBoard()" style="'+ib+'width:36px;flex-shrink:0;" title="Retour au visio">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="18" height="18"><path d="M3 9l9-7 9 7v11a2 2 0 01-2 2H5a2 2 0 01-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg></button>'
    +'<div style="width:1px;background:rgba(255,255,255,.16);margin:8px 4px;flex-shrink:0;"></div>'
    // Page tabs : flex:1 pour partager la largeur disponible, se réduisent automatiquement
    +'<div id="_brdTabs" style="flex:1;display:flex;align-items:flex-end;gap:2px;padding:6px 4px 0;min-width:0;overflow:hidden;"></div>'
    +(_isOwner?'<button onclick="_boardAddPage()" style="'+ib+'width:34px;font-size:20px;" title="Nouvelle page">+</button>':'')
    +'<div style="width:1px;background:rgba(255,255,255,.16);margin:8px 3px;flex-shrink:0;"></div>'
    +'<button id="_bU" onclick="_boardUndo()" style="'+ib+'width:36px;" title="Annuler">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="17" height="17"><path d="M9 14L4 9l5-5"/><path d="M4 9h10.5a5.5 5.5 0 010 11H11"/></svg></button>'
    +'<button id="_bRd" onclick="_boardRedo()" style="'+ib+'width:36px;" title="Refaire">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="17" height="17"><path d="M15 14l5-5-5-5"/><path d="M20 9H9.5a5.5 5.5 0 000 11H13"/></svg></button>'
    +'</div>'  // close nav content row
    +'</div>'  // close outer blue wrapper
    // ── Floating glass pill : scrollable pour accommoder tous les boutons ──
    +'<div id="_brdFloatBar" style="position:fixed;top:calc(max(env(safe-area-inset-top,20px),20px) + 54px);left:12px;max-width:calc(100vw - 24px);z-index:150;background:rgba(12,16,38,.52);backdrop-filter:blur(14px);-webkit-backdrop-filter:blur(14px);border-radius:50px;border:0.5px solid rgba(255,255,255,.14);box-shadow:0 4px 22px rgba(0,0,0,.38);overflow:hidden;">'
    +'<div style="display:flex;align-items:center;gap:2px;padding:4px 6px;overflow-x:auto;scrollbar-width:none;-webkit-overflow-scrolling:touch;-ms-overflow-style:none;">'
    +'<button onclick="_vCloseBoard()" style="'+glassBtn+'flex-shrink:0;" title="Retour">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" width="18" height="18"><polyline points="15 18 9 12 15 6"/></svg></button>'
    +(_isOwner
      ?'<div style="'+glassSep+'margin:0 2px;flex-shrink:0;"></div>'
      +'<button onclick="_vTimerOpen()" style="'+glassBtn+'flex-shrink:0;" title="Minuteur">'
      +'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="17" height="17"><circle cx="12" cy="13" r="8"/><polyline points="12 9 12 13 15 16"/><line x1="9" y1="2" x2="15" y2="2"/><line x1="12" y1="2" x2="12" y2="5"/></svg></button>'
      :''
    )
    +'<div style="'+glassSep+'margin:0 2px;flex-shrink:0;"></div>'
    +'<button onclick="_vToggleComment()" style="'+glassBtn+'flex-shrink:0;" title="Commentaires">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="17" height="17"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg></button>'
    +'<div style="'+glassSep+'margin:0 2px;flex-shrink:0;"></div>'
    // Télécharger image PNG du tableau
    +'<button onclick="_boardExport()" style="'+glassBtn+'flex-shrink:0;" title="Télécharger en image PNG">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="17" height="17"><path d="M23 19a2 2 0 01-2 2H3a2 2 0 01-2-2V8a2 2 0 012-2h4l2-3h6l2 3h4a2 2 0 012 2z"/><circle cx="12" cy="13" r="4"/></svg></button>'
    +'<div style="'+glassSep+'margin:0 2px;flex-shrink:0;"></div>'
    // Sauvegarder / restaurer le tableau (format .cpboard — à réimporter dans CoursPool)
    +'<button onclick="_boardExportCP()" style="'+glassBtn+'flex-shrink:0;" title="Sauvegarder le tableau (à réimporter dans CoursPool)">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="#60a5fa" stroke-width="2" stroke-linecap="round" width="17" height="17"><path d="M19 21H5a2 2 0 01-2-2V5a2 2 0 012-2h11l5 5v13a2 2 0 01-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg></button>'
    +'<button onclick="_boardImportCP()" style="'+glassBtn+'flex-shrink:0;" title="Restaurer un tableau sauvegardé">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="#a78bfa" stroke-width="2" stroke-linecap="round" width="17" height="17"><path d="M3 15v4a2 2 0 002 2h14a2 2 0 002-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg></button>'
    +'<div style="'+glassSep+'margin:0 2px;flex-shrink:0;"></div>'
    +'<button id="_brdBgBtn" onclick="_boardToggleBg()" style="'+glassBtn+'flex-shrink:0;" title="Fond vierge / quadrillé">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" width="17" height="17"><rect x="3" y="3" width="18" height="18" rx="2"/><line x1="3" y1="9" x2="21" y2="9"/><line x1="3" y1="15" x2="21" y2="15"/><line x1="9" y1="3" x2="9" y2="21"/><line x1="15" y1="3" x2="15" y2="21"/></svg></button>'
    +(_isOwner
      ?'<div style="'+glassSep+'margin:0 2px;flex-shrink:0;"></div>'
      +'<button id="_brdSyncBtn" onclick="_boardForceSyncAll()" style="'+glassBtn+'flex-shrink:0;" title="Synchroniser le tableau pour tous les élèves">'
      +'<svg viewBox="0 0 24 24" fill="none" stroke="#4ade80" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" width="17" height="17"><polyline points="1 4 1 10 7 10"/><polyline points="23 20 23 14 17 14"/><path d="M20.49 9A9 9 0 0 0 5.64 5.64L1 10m22 4l-4.64 4.36A9 9 0 0 1 3.51 15"/></svg></button>'
      :''
    )
    +'<div style="'+glassSep+'margin:0 2px;flex-shrink:0;"></div>'
    +'<button onclick="_boardClearCurrentPage()" style="'+glassBtn+'flex-shrink:0;" title="Effacer la page (double-tap)">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="2" stroke-linecap="round" width="17" height="17"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/><path d="M9 6V4a1 1 0 011-1h4a1 1 0 011 1v2"/></svg></button>'
    +'</div>'  // close scrollable inner row
    +'</div>'  // close floating bar wrapper
    // Badge lecture seule (élève sans permission)
    +'<div id="_brdLockBadge" style="display:none;position:fixed;top:max(env(safe-area-inset-top,20px),20px);left:50%;transform:translateX(-50%);z-index:200;background:rgba(20,20,35,.88);border-radius:20px;padding:5px 12px;display:none;align-items:center;gap:5px;pointer-events:none;">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="#facc15" stroke-width="2" stroke-linecap="round" width="12" height="12"><rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0110 0v4"/></svg>'
    +'<span style="font-size:11px;font-weight:600;color:#facc15;">Lecture seule</span>'
    +'</div>'
    // Panneau permissions prof (liste participants + boutons Autoriser)
    +(_isOwner?'<div id="_brdPermPanel" style="display:none;position:fixed;right:12px;top:max(calc(env(safe-area-inset-top,20px)+72px),92px);z-index:200;background:rgba(20,20,35,.92);backdrop-filter:blur(12px);border-radius:14px;padding:10px 12px;min-width:160px;box-shadow:0 4px 24px rgba(0,0,0,.4);"></div>':'')
    // Canvas zone: gray bg, centered white page, floating pill at bottom
    +'<div id="_brdScroll" style="flex:1;background:#d4d4d9;display:flex;align-items:center;justify-content:center;overflow:hidden;touch-action:none;position:relative;">'
    +'<div id="_brdPage" style="background:#fff;box-shadow:0 3px 28px rgba(0,0,0,.18),0 1px 4px rgba(0,0,0,.08);position:relative;flex-shrink:0;">'
    +'<canvas id="_vBoardBg" style="position:absolute;top:0;left:0;pointer-events:none;display:block;"></canvas>'
    +'<canvas id="_vBoardCanvas" style="display:block;touch-action:none;position:relative;"></canvas>'
    +'</div>'
    // Floating bottom pill toolbar (like app nav bar)
    +'<div id="_brdSub" style="position:absolute;bottom:max(env(safe-area-inset-bottom,16px),16px);left:50%;transform:translateX(-50%);display:flex;align-items:center;background:rgba(30,30,40,.92);backdrop-filter:blur(18px);-webkit-backdrop-filter:blur(18px);border-radius:36px;box-shadow:0 8px 32px rgba(0,0,0,.32),0 0 0 1px rgba(255,255,255,.10);padding:6px 10px;gap:3px;overflow-x:auto;scrollbar-width:none;max-width:calc(100% - 32px);touch-action:manipulation;z-index:10;"></div>'
    // Rotate-phone overlay (portrait phone only)
    +'<div id="_brdRotate" style="display:none;position:absolute;inset:0;z-index:30;background:#0c0e14;flex-direction:column;align-items:center;justify-content:center;gap:18px;pointer-events:none;">'
    +'<div id="_brdRotIcon" style="font-size:0;">'
    +'<svg viewBox="0 0 80 80" fill="none" width="72" height="72">'
    +'<rect x="22" y="8" width="36" height="56" rx="6" stroke="#FF6B2B" stroke-width="3"/>'
    +'<circle cx="40" cy="57" r="3" fill="#FF6B2B" opacity=".6"/>'
    +'<path d="M58 26l8 8-8 8" stroke="rgba(255,255,255,.35)" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/>'
    +'<line x1="66" y1="34" x2="76" y2="34" stroke="rgba(255,255,255,.35)" stroke-width="2.5" stroke-linecap="round"/>'
    +'</svg>'
    +'</div>'
    +'<div style="font-size:16px;font-weight:700;color:#fff;text-align:center;line-height:1.4;padding:0 40px;">Tourne ton téléphone</div>'
    +'<div style="font-size:13px;color:rgba(255,255,255,.45);text-align:center;">Le tableau est optimisé en mode paysage</div>'
    +'</div>'
    +'</div>';
}

// Renders the complete sub-toolbar pill based on current tool/color/size
function _boardRenderSubbar(){
  var sub=g('_brdSub');if(!sub)return;
  var h='';
  // Lecture seule : dimmer les outils de dessin
  var readOnly=(_brdRoomId&&!_brdCanEdit);
  if(readOnly)sub.style.opacity='0.45';else sub.style.opacity='';
  // Dark pill → light icon colors
  var ic='rgba(255,255,255,.80)';  // inactive icon stroke
  var tb=function(id,onclick,active,svg,title,toolName){
    var pinned=toolName&&_brdPinnedTool===toolName;
    var bg=active?'background:rgba(255,255,255,.18);':'background:transparent;';
    var pinSt=pinned?'box-shadow:inset 0 -2.5px 0 #FF6B2B;':'';
    var pdHandlers=toolName
      ?'onpointerdown="_brdToolPD(\''+toolName+'\')" onpointerup="_brdToolPU()" onpointerleave="_brdToolPU()" onpointercancel="_brdToolPU()"'
      :'';
    return '<button id="'+id+'" onclick="'+onclick+'" '+pdHandlers+' title="'+(title||'')+'" style="'+bg+pinSt+'border:none;cursor:pointer;width:38px;height:36px;border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0;-webkit-tap-highlight-color:transparent;transition:background .1s;">'
      +svg+'</button>';
  };
  var sep='<div style="width:1px;height:24px;background:rgba(255,255,255,.15);margin:0 4px;flex-shrink:0;"></div>';
  // ── Tool icons ──
  h+=tb('_bTHd',"_boardToolTap('hand')",_brdTool==='hand',
    '<svg viewBox="0 0 24 24" fill="none" stroke="'+(_brdTool==='hand'?'#FF6B2B':ic)+'" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" width="19" height="19"><path d="M18 11V8a2 2 0 00-4 0v3"/><path d="M14 8V6a2 2 0 00-4 0v5"/><path d="M10 6.5V5a2 2 0 00-4 0v8"/><path d="M6 13s0 5 4 7h4c3 0 4-2 4-4v-5a2 2 0 00-4 0"/></svg>'
    ,'Déplacer (H / espace)','hand');
  h+=tb('_bTSl',"_boardToolTap('select')",_brdTool==='select',
    '<svg viewBox="0 0 24 24" fill="none" stroke="'+(_brdTool==='select'?'#FF6B2B':ic)+'" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" width="19" height="19"><path d="M5 3l14 9-7 1-4 7z"/></svg>'
    ,'Sélection (S)','select');
  h+=tb('_bTLs',"_boardToolTap('laser')",_brdTool==='laser',
    '<svg viewBox="0 0 24 24" fill="none" stroke="'+(_brdTool==='laser'?'#ef4444':ic)+'" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" width="19" height="19"><circle cx="12" cy="12" r="2.5" fill="'+(_brdTool==='laser'?'#ef4444':'none')+'"/><line x1="12" y1="2" x2="12" y2="5"/><line x1="12" y1="19" x2="12" y2="22"/><line x1="2" y1="12" x2="5" y2="12"/><line x1="19" y1="12" x2="22" y2="12"/><line x1="5.6" y1="5.6" x2="7" y2="7"/><line x1="17" y1="17" x2="18.4" y2="18.4"/><line x1="5.6" y1="18.4" x2="7" y2="17"/><line x1="17" y1="7" x2="18.4" y2="5.6"/></svg>'
    ,'Pointeur laser (L)','laser');
  h+=sep;
  h+=tb('_bTPen',"_boardToolTap('pen')",_brdTool==='pen',
    '<svg viewBox="0 0 24 24" fill="none" stroke="'+(_brdTool==='pen'?'#FF6B2B':ic)+'" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" width="19" height="19"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/></svg>'
    ,'Stylo','pen');
  h+=tb('_bTEr',"_boardToolTap('eraser')",_brdTool==='eraser',
    '<svg viewBox="0 0 24 24" fill="none" stroke="'+(_brdTool==='eraser'?'#FF6B2B':ic)+'" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" width="19" height="19"><path d="M3 21h18"/><path d="M6.5 21L3 16l9.5-9.5 6 6L12 19.5"/><path d="M12.5 6.5l6 6"/></svg>'
    ,'Gomme','eraser');
  h+=tb('_bTTx',"_boardToolTap('text')",_brdTool==='text',
    '<svg viewBox="0 0 24 24" fill="none" stroke="'+(_brdTool==='text'?'#FF6B2B':ic)+'" stroke-width="1.8" stroke-linecap="round" width="19" height="19"><polyline points="4 7 4 4 20 4 20 7"/><line x1="9" y1="20" x2="15" y2="20"/><line x1="12" y1="4" x2="12" y2="20"/></svg>'
    ,'Texte','text');
  h+=tb('_bTSh',"_boardToolTap('shape')",_brdTool==='shape',
    '<svg viewBox="0 0 24 24" fill="none" stroke="'+(_brdTool==='shape'?'#FF6B2B':ic)+'" stroke-width="1.8" stroke-linecap="round" width="19" height="19"><rect x="3" y="3" width="8" height="8" rx="1.5"/><circle cx="17" cy="7" r="4"/><path d="M12 22l4.5-8h-9z"/></svg>'
    ,'Formes','shape');
  // Bouton image — ouvre le sélecteur de fichier
  h+='<button onclick="_boardInsertImageBtn()" title="Insérer une image (max 5 Mo)" style="background:transparent;border:none;cursor:pointer;width:38px;height:36px;border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0;-webkit-tap-highlight-color:transparent;transition:background .1s;" onmouseover="this.style.background=\'rgba(255,255,255,.1)\'" onmouseout="this.style.background=\'transparent\'">'
    +'<svg viewBox="0 0 24 24" fill="none" stroke="'+ic+'" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" width="19" height="19"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg></button>';
  h+=sep;
  // ── Context-sensitive: sizes or shape picker ──
  if(_brdTool==='shape'){
    var shapes=[{t:'rect',svg:'<rect x="3" y="5" width="18" height="14" rx="1.5"/>'},
      {t:'circle',svg:'<circle cx="12" cy="12" r="9"/>'},
      {t:'tri',svg:'<path d="M12 3l10 18H2z"/>'},
      {t:'diamond',svg:'<path d="M12 3l9 9-9 9-9-9z"/>'},
      {t:'line',svg:'<line x1="4" y1="20" x2="20" y2="4"/>'},
      {t:'arrow',svg:'<line x1="4" y1="20" x2="20" y2="4"/><polyline points="14 4 20 4 20 10"/>'}];
    shapes.forEach(function(sh){
      var a=_brdShType===sh.t;
      h+='<button onclick="_boardSetShape(\''+sh.t+'\')" style="background:'+(a?'rgba(255,255,255,.18)':'transparent')+';border:none;cursor:pointer;width:36px;height:36px;border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
        +'<svg viewBox="0 0 24 24" fill="none" stroke="'+(a?'#FF6B2B':ic)+'" stroke-width="1.9" stroke-linecap="round" width="17" height="17">'+sh.svg+'</svg></button>';
    });
    h+=sep;
    // Fill toggle
    h+='<button onclick="_boardToggleShFill()" title="Remplissage" style="background:'+(_brdShFill?'rgba(255,255,255,.18)':'transparent')+';border:none;cursor:pointer;width:36px;height:36px;border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
      +'<svg viewBox="0 0 24 24" fill="'+(_brdShFill?'rgba(255,255,255,.55)':'none')+'" stroke="'+(_brdShFill?'#FF6B2B':ic)+'" stroke-width="1.8" stroke-linecap="round" width="17" height="17"><rect x="3" y="3" width="18" height="18" rx="2"/></svg></button>';
    h+=sep;
    // Stroke sizes
    [{sz:2,h:2},{sz:5,h:5},{sz:11,h:9}].forEach(function(s){
      var a=_brdSz===s.sz;
      h+='<button onclick="_boardSetSize('+s.sz+')" style="background:'+(a?'rgba(255,255,255,.18)':'transparent')+';border:none;cursor:pointer;width:40px;height:36px;border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
        +'<div style="width:28px;height:'+s.h+'px;background:'+(a?_brdColor:'rgba(255,255,255,.4)')+';border-radius:'+(s.h/2)+'px;"></div></button>';
    });
  }else if(_brdTool==='text'){
    // Text tool: sizes, bold/italic, alignment (no separate color picker — uses main _brdColor)
    [{sz:12,lbl:'S'},{sz:16,lbl:'M'},{sz:22,lbl:'L'},{sz:30,lbl:'XL'}].forEach(function(s){
      var a=_brdTextSize===s.sz;
      h+='<button onmousedown="event.preventDefault();_brdSetTextSz('+s.sz+')" ontouchstart="event.preventDefault();_brdSetTextSz('+s.sz+')" style="background:'+(a?'rgba(255,255,255,.18)':'transparent')+';border:none;cursor:pointer;width:32px;height:34px;border-radius:10px;font-family:inherit;font-size:11px;font-weight:600;color:'+(a?'#fff':'rgba(255,255,255,.55)')+';-webkit-tap-highlight-color:transparent;flex-shrink:0;">'+s.lbl+'</button>';
    });
    h+=sep;
    h+='<button onmousedown="event.preventDefault();_brdToggleBold()" ontouchstart="event.preventDefault();_brdToggleBold()" style="background:'+(_brdTextBold?'rgba(255,255,255,.18)':'transparent')+';border:none;cursor:pointer;width:32px;height:34px;border-radius:10px;font-family:inherit;font-size:14px;font-weight:700;color:'+(_brdTextBold?'#fff':'rgba(255,255,255,.55)')+';-webkit-tap-highlight-color:transparent;flex-shrink:0;">B</button>';
    h+='<button onmousedown="event.preventDefault();_brdToggleItalic()" ontouchstart="event.preventDefault();_brdToggleItalic()" style="background:'+(_brdTextItalic?'rgba(255,255,255,.18)':'transparent')+';border:none;cursor:pointer;width:32px;height:34px;border-radius:10px;font-family:inherit;font-size:14px;font-style:italic;font-weight:600;color:'+(_brdTextItalic?'#fff':'rgba(255,255,255,.55)')+';-webkit-tap-highlight-color:transparent;flex-shrink:0;"><i>I</i></button>';
    h+=sep;
    var alignSvgs={left:'<line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="15" y2="12"/><line x1="3" y1="18" x2="18" y2="18"/>',center:'<line x1="3" y1="6" x2="21" y2="6"/><line x1="6" y1="12" x2="18" y2="12"/><line x1="4" y1="18" x2="20" y2="18"/>',right:'<line x1="3" y1="6" x2="21" y2="6"/><line x1="9" y1="12" x2="21" y2="12"/><line x1="6" y1="18" x2="21" y2="18"/>'};
    ['left','center','right'].forEach(function(al){
      var a=_brdTextAlign===al;
      h+='<button onmousedown="event.preventDefault();_brdSetAlign(\''+al+'\')" ontouchstart="event.preventDefault();_brdSetAlign(\''+al+'\')" style="background:'+(a?'rgba(255,255,255,.18)':'transparent')+';border:none;cursor:pointer;width:32px;height:34px;border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0;-webkit-tap-highlight-color:transparent;">'
        +'<svg viewBox="0 0 24 24" fill="none" stroke="'+(a?'#FF6B2B':ic)+'" stroke-width="2" stroke-linecap="round" width="16" height="16">'+alignSvgs[al]+'</svg></button>';
    });
  }else if(_brdTool==='eraser'){
    [{sz:14,h:3},{sz:28,h:6},{sz:52,h:11}].forEach(function(s){
      var a=_brdEr===s.sz;
      h+='<button onclick="_boardSetEraserSz('+s.sz+')" style="background:'+(a?'rgba(255,255,255,.18)':'transparent')+';border:none;cursor:pointer;width:42px;height:36px;border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
        +'<div style="width:28px;height:'+s.h+'px;background:'+(a?'#fff':'rgba(255,255,255,.4)')+';border-radius:2px;"></div></button>';
    });
  }else if(_brdTool==='pen'||_brdTool==='marker'){
    [{sz:2,h:2},{sz:5,h:5},{sz:11,h:9}].forEach(function(s){
      var a=_brdSz===s.sz;
      h+='<button onclick="_boardSetSize('+s.sz+')" style="background:'+(a?'rgba(255,255,255,.18)':'transparent')+';border:none;cursor:pointer;width:42px;height:36px;border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
        +'<div style="width:30px;height:'+s.h+'px;background:'+(a?_brdColor:'rgba(255,255,255,.4)')+';border-radius:'+(s.h/2)+'px;"></div></button>';
    });
  }
  // ── Colors (not eraser, not select) ──
  if(_brdTool==='select'){
    h+='<span style="font-size:11px;font-weight:600;color:rgba(255,255,255,.45);white-space:nowrap;padding:0 10px;letter-spacing:.01em;">Glissez pour sélectionner</span>';
  }
  if(_brdTool==='laser'){
    h+='<span style="font-size:11px;font-weight:600;color:rgba(239,68,68,.7);white-space:nowrap;padding:0 10px;letter-spacing:.01em;">Pointez sans dessiner</span>';
  }
  if(_brdTool!=='eraser'&&_brdTool!=='select'&&_brdTool!=='laser'){
    h+=sep;
    _BC.forEach(function(c){
      var a=c===_brdColor;
      h+='<button onclick="_boardSetColor(\''+c+'\')" style="width:26px;height:26px;border-radius:50%;background:'+c+';border:none;cursor:pointer;flex-shrink:0;-webkit-tap-highlight-color:transparent;margin:0 2px;'
        +(a?'box-shadow:0 0 0 2px rgba(30,30,40,.9),0 0 0 4px '+c+';':'box-shadow:0 0 0 1.5px rgba(255,255,255,.25);')
        +'"></button>';
    });
    h+='<label style="width:26px;height:26px;border-radius:50%;background:conic-gradient(red,#ff0,lime,cyan,blue,magenta,red);cursor:pointer;flex-shrink:0;position:relative;display:block;box-shadow:0 0 0 1.5px rgba(255,255,255,.25);margin:0 2px;overflow:hidden;">'
      +'<input type="color" value="'+_brdColor+'" oninput="_boardSetColor(this.value)" style="opacity:0;position:absolute;inset:0;width:100%;height:100%;cursor:pointer;border:none;padding:0;"></label>';
  }
  sub.innerHTML=h;
}

function _vOpenBoard(){
  if(window.innerWidth<768){
    var _bPop=document.createElement('div');
    _bPop.id='_vBoardPop';
    _bPop.style.cssText='position:fixed;inset:0;z-index:99999;display:flex;align-items:center;justify-content:center;padding:24px;';
    _bPop.innerHTML='<div style="background:#1a1a2e;border:1px solid rgba(255,255,255,.1);border-radius:20px;padding:28px 24px;max-width:320px;width:100%;text-align:center;box-shadow:0 24px 60px rgba(0,0,0,.6);">'
      +'<div style="display:flex;align-items:center;justify-content:center;width:56px;height:56px;border-radius:16px;background:rgba(255,107,43,.15);margin:0 auto 16px;">'
      +'<svg viewBox="0 0 24 24" fill="none" stroke="#FF6B2B" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" width="28" height="28"><rect x="2" y="3" width="20" height="14" rx="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>'
      +'</div>'
      +'<div style="font-size:16px;font-weight:800;color:#fff;margin-bottom:10px">Tableau collaboratif</div>'
      +'<div style="font-size:13.5px;color:rgba(255,255,255,.6);line-height:1.6;margin-bottom:22px">Le tableau collaboratif est disponible sur iPad et ordinateur uniquement. Sur téléphone, profite du cours en visio !</div>'
      +'<button id="_vBoardPopOk" style="width:100%;padding:12px;background:#FF6B2B;border:none;border-radius:12px;color:#fff;font-size:14px;font-weight:700;font-family:inherit;cursor:pointer;-webkit-tap-highlight-color:transparent;">OK, compris</button>'
      +'</div>';
    _bPop.onclick=function(e){if(e.target===_bPop)_bPop.remove();};
    document.body.appendChild(_bPop);
    var _bOk=g('_vBoardPopOk');
    if(_bOk)_bOk.onclick=function(){var p=g('_vBoardPop');if(p)p.remove();};
    return;
  }
  if(_boardActive)return;
  _boardActive=true;
  var bdV=g('bdVisio');if(!bdV)return;
  var grid=g('_vGrid');if(!grid)return;
  if(!_brdPages.length)_brdPages.push(null);
  // ── Init room collaborative ──────────────────────────────────
  _brdRoomId=null;_brdCanEdit=false;_brdParticipants=[];
  if(!_isDemoMode&&typeof _socket!=='undefined'&&_socket&&_socket.connected&&_visioCurrentUrl){
    var _rId=_visioCurrentUrl.split('/').pop();
    if(_rId){
      _brdRoomId=_rId;
      var _uName=(user&&(user.prenom||user.email))||'?';
      if(_isOwner){
        _brdCanEdit=true;
        _socket.emit('board_init',{roomId:_brdRoomId,userName:_uName});
      }else{
        _socket.emit('board_join',{roomId:_brdRoomId,userName:_uName});
      }
    }
  }else if(_isDemoMode){
    _brdCanEdit=true; // démo = local, tout autorisé
  }
  // PiP setup
  var sw=_PW[_pipSzIdx],sh=_PH[_pipSzIdx];
  if(_pipX===null)_pipX=window.innerWidth-sw-20;
  if(_pipY===null)_pipY=window.innerHeight-sh-100;
  var pip=document.createElement('div');
  pip.id='_vPip';
  pip.style.cssText='position:fixed;z-index:10050;border-radius:16px;overflow:hidden;box-shadow:0 8px 40px rgba(0,0,0,.5),0 0 0 1px rgba(255,255,255,.08);width:'+sw+'px;height:'+sh+'px;left:'+_pipX+'px;top:'+_pipY+'px;background:#0d0d18;user-select:none;-webkit-user-select:none;touch-action:none;transform:scale(0.82);opacity:0;transition:transform 380ms cubic-bezier(.34,1.56,.64,1),opacity 220ms ease;';
  grid.style.cssText='position:absolute;inset:0;display:grid;gap:4px;padding:4px;box-sizing:border-box;background:#0d0d18;';
  // Hide all tiles before appending to prevent flash of all participants
  grid.querySelectorAll('[id^="_vt-"]').forEach(function(t){t.style.display='none';});
  _vPipFeaturedSid=null; // reset so _vApplyLayout picks the right featured tile
  pip.appendChild(grid);
  // Drag handle — single hide-bubble button
  var ph=document.createElement('div');
  ph.style.cssText='position:absolute;top:0;left:0;right:0;height:30px;background:linear-gradient(rgba(0,0,0,.55),transparent);z-index:3;display:flex;align-items:center;justify-content:flex-end;padding:5px 6px;touch-action:none;cursor:grab;';
  var bs='background:rgba(0,0,0,.45);border:none;color:#fff;width:22px;height:22px;border-radius:6px;cursor:pointer;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(6px);flex-shrink:0;-webkit-tap-highlight-color:transparent;';
  // Resize button — cycles through predefined pip sizes
  var rsz=document.createElement('button');rsz.style.cssText=bs+'margin-right:4px;';
  rsz.title='Redimensionner la bulle';
  rsz.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.5" stroke-linecap="round" width="12" height="12"><polyline points="15 3 21 3 21 9"/><polyline points="9 21 3 21 3 15"/><line x1="21" y1="3" x2="14" y2="10"/><line x1="3" y1="21" x2="10" y2="14"/></svg>';
  rsz.onclick=function(e){e.stopPropagation();_pipCycleSize();};
  var hb=document.createElement('button');hb.style.cssText=bs;
  hb.title='Masquer la bulle';
  hb.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.5" stroke-linecap="round" width="12" height="12"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/></svg>';
  // Restore badge (shown when pip is hidden)
  var rb=document.createElement('button');
  rb.id='_vPipRestoreBtn';
  rb.style.cssText='position:fixed;z-index:10051;width:44px;height:44px;border-radius:50%;background:rgba(13,13,24,.9);border:1.5px solid rgba(255,255,255,.15);color:#fff;cursor:pointer;display:none;align-items:center;justify-content:center;box-shadow:0 4px 18px rgba(0,0,0,.5);-webkit-tap-highlight-color:transparent;backdrop-filter:blur(10px);left:'+(_pipX+sw/2-22)+'px;top:'+(_pipY+sh/2-22)+'px;transition:transform .18s cubic-bezier(.34,1.56,.64,1);';
  rb.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2" stroke-linecap="round" width="18" height="18"><path d="M23 7l-7 5 7 5V7z"/><rect x="1" y="5" width="15" height="14" rx="2"/></svg>';
  hb.onclick=function(e){
    e.stopPropagation();
    pip.style.transition='transform .22s ease,opacity .18s ease';
    pip.style.transform='scale(0.1)';pip.style.opacity='0';pip.style.pointerEvents='none';
    rb.style.display='flex';
    requestAnimationFrame(function(){rb.style.transform='scale(1)';});
  };
  // Restore badge: tap = show pip, drag = move badge
  var _rbSX=0,_rbSY=0,_rbOX=0,_rbOY=0,_rbMoved=false,_rbDown=false;
  rb.addEventListener('pointerdown',function(e){
    e.preventDefault();
    _rbDown=true;_rbMoved=false;
    _rbSX=e.clientX;_rbSY=e.clientY;
    _rbOX=parseInt(rb.style.left)||0;_rbOY=parseInt(rb.style.top)||0;
    rb.setPointerCapture(e.pointerId);
    rb.style.transition='none';
  },{passive:false});
  rb.addEventListener('pointermove',function(e){
    if(!_rbDown)return; // survol sans clic → ne pas déplacer
    var dx=e.clientX-_rbSX,dy=e.clientY-_rbSY;
    if(!_rbMoved&&Math.hypot(dx,dy)<12)return;
    _rbMoved=true;
    e.preventDefault();
    rb.style.left=Math.max(0,Math.min(window.innerWidth-44,_rbOX+dx))+'px';
    rb.style.top=Math.max(0,Math.min(window.innerHeight-44,_rbOY+dy))+'px';
  },{passive:false});
  rb.addEventListener('pointerup',function(){
    _rbDown=false;
    if(_rbMoved){_rbMoved=false;return;} // drag → ne pas afficher le pip
    rb.style.display='none';
    pip.style.transition='transform 300ms cubic-bezier(.34,1.56,.64,1),opacity .18s ease';
    pip.style.transform='scale(1)';pip.style.opacity='1';pip.style.pointerEvents='';
  },{passive:true});
  rb.addEventListener('pointercancel',function(){_rbDown=false;_rbMoved=false;},{passive:true});
  document.body.appendChild(rb);
  ph.appendChild(rsz);ph.appendChild(hb);
  pip.appendChild(ph);
  document.body.appendChild(pip);
  // Apply layout now that pip is in the document (getElementById works)
  _vApplyLayout();
  // Spring entrance animation
  requestAnimationFrame(function(){pip.style.transform='scale(1)';pip.style.opacity='1';});
  // Double-tap → expand pip back to full visio
  var _pipDblTapT=0;
  pip.addEventListener('click',function(e){
    if(e.target===hb||hb.contains(e.target))return; // ignore hide button
    if(e.target===rsz||rsz.contains(e.target))return; // ignore resize button
    var now=Date.now();
    if(now-_pipDblTapT<320){
      _pipDblTapT=0;
      var r=pip.getBoundingClientRect();
      var scaleX=window.innerWidth/r.width,scaleY=window.innerHeight/r.height;
      var sc=Math.max(scaleX,scaleY)*1.05;
      var dx=window.innerWidth/2-(r.left+r.width/2);
      var dy=window.innerHeight/2-(r.top+r.height/2);
      pip.style.transition='transform 320ms cubic-bezier(.4,0,.2,1),opacity 260ms ease,border-radius 300ms ease';
      pip.style.transform='translate('+dx+'px,'+dy+'px) scale('+sc+')';
      pip.style.borderRadius='0';
      pip.style.opacity='0';
      setTimeout(function(){_vCloseBoard();},300);
    }else{
      _pipDblTapT=now;
    }
  },{passive:true});
  _pipInitDrag(ph,pip);
  _pipInitPinch(pip);
  // Board overlay
  var bo=document.createElement('div');
  bo.id='_vBoardOuter';
  // Emil: prevent jarring appearance — fade+scale in
  bo.style.cssText='position:absolute;inset:0;z-index:4;display:flex;flex-direction:column;overflow:hidden;opacity:0;transform:scale(.98);transition:opacity 180ms ease-out,transform 220ms cubic-bezier(.22,.61,.36,1);';
  bo.innerHTML=_buildBoardInner();
  bdV.appendChild(bo);
  // Sortir _vComment et _vCommentTab de _vMain (overflow:hidden → stacking context)
  // pour les rendre frères de _vBoardOuter → z-index:10 bat z-index:4
  var _vcEl=g('_vComment'),_vtEl=g('_vCommentTab');
  if(_vcEl)bdV.appendChild(_vcEl);
  if(_vtEl)bdV.appendChild(_vtEl);
  requestAnimationFrame(function(){bo.style.opacity='1';bo.style.transform='scale(1)';_boardInitCanvas();});
  var btn=g('_vBoardBtn');
  if(btn){btn.style.background='rgba(255,107,43,.55)';btn.style.boxShadow='0 0 0 2px #FF6B2B,0 4px 18px rgba(255,107,43,.35)';}
  haptic(1);
}

function _vCloseBoard(){
  if(!_boardActive)return;
  _boardActive=false;
  if(_brdSel.active)_brdCommitSel();
  if(_brdRoomId&&typeof _socket!=='undefined'&&_socket&&_socket.connected){
    _socket.emit('board_leave',{roomId:_brdRoomId});
  }
  if(typeof _brdCleanRemoteCursors==='function')_brdCleanRemoteCursors();
  // Annuler les RAFs curseur en attente pour éviter des accès DOM post-fermeture
  Object.keys(_brdCursorRAF).forEach(function(id){cancelAnimationFrame(_brdCursorRAF[id]);});
  _brdCursorRAF={};_brdCursorPt={};
  _brdRoomId=null;_brdCanEdit=false;_brdParticipants=[];
  _brdBgType='grid';
  _brdCleanObjSel();_brdObjects=[];_brdObjPages=[];
  _brdPinnedTool=null;_brdTool='pen';_brdActivePointers={};
  clearInterval(_vTimerIv);_vTimerRunning=false;
  _vPipFeaturedSid=null;
  if(_brdOrientHandler){window.removeEventListener('resize',_brdOrientHandler);_brdOrientHandler=null;}
  if(_brdKeyHandler){document.removeEventListener('keydown',_brdKeyHandler);_brdKeyHandler=null;}
  if(_brdKeyUpHandler){document.removeEventListener('keyup',_brdKeyUpHandler);_brdKeyUpHandler=null;}
  _brdSpacePanning=false;_brdSpacePrevTool=null;
  _brdCleanLaserDot();
  Object.keys(_brdLaserHideT).forEach(function(id){clearTimeout(_brdLaserHideT[id]);});
  _brdLaserHideT={};
  if(_brdSnapTimer){clearTimeout(_brdSnapTimer);_brdSnapTimer=null;}
  if(_brdLPTimer){clearTimeout(_brdLPTimer);_brdLPTimer=null;}
  _brdCleanEraserCursor();
  // Nettoyer l'éditeur de texte si une saisie est en cours (évite les éléments orphelins dans body)
  var _aInp=document.getElementById('_brdActiveInp');if(_aInp&&_aInp.parentNode)_aInp.parentNode.removeChild(_aInp);
  var _aTBar=document.getElementById('_brdTxtBar');if(_aTBar&&_aTBar.parentNode)_aTBar.parentNode.removeChild(_aTBar);
  _brdActiveTxtBarEl=null;_brdTextAnchor=null;
  if(_brdC&&_brdPages.length>0&&!_brdRestorePending){try{_boardSavePage();}catch(e){}}
  _brdRestorePending=false;_brdRestoreEpoch=0;
  var bo=g('_vBoardOuter');if(bo)bo.remove();
  // Remettre _vComment et _vCommentTab dans _vMain
  var _vmEl=g('_vMain');
  var _vcEl=g('_vComment'),_vtEl=g('_vCommentTab');
  if(_vcEl&&_vmEl)_vmEl.appendChild(_vcEl);
  if(_vtEl&&_vmEl)_vmEl.appendChild(_vtEl);
  var pip=g('_vPip');var grid=g('_vGrid');
  var rb=g('_vPipRestoreBtn');if(rb)rb.remove();
  if(pip&&grid){
    if(grid.parentNode===pip)pip.removeChild(grid);
    var main=g('_vMain');var people=g('_vPeople');
    if(main)main.insertBefore(grid,people||null);
    pip.remove();
  }
  if(grid){grid.style.cssText='flex:1;display:grid;gap:8px;overflow:hidden;background:#0d0d18;padding:8px;min-height:0;';_vApplyLayout();}
  var btn=g('_vBoardBtn');if(btn){btn.style.background='rgba(255,255,255,.12)';btn.style.boxShadow='';}
  haptic(1);
}

// Stored resize listener so we can remove it when closing
var _brdOrientHandler=null;
var _brdKeyHandler=null;
// Epoch counter: prevents superseded async restores from drawing to the canvas
var _brdRestoreEpoch=0;
var _brdRestorePending=false; // true while an async _boardRestorePage is in flight

function _brdIsPhonePortrait(){
  // Phone class: smallest screen dimension < 500px AND currently portrait
  return window.innerWidth < window.innerHeight && Math.min(screen.width,screen.height)<500;
}
function _brdCheckOrientation(){
  var rotEl=g('_brdRotate');
  var canv=g('_vBoardCanvas');
  var bgC=g('_vBoardBg');
  var page=g('_brdPage');
  var scroll=g('_brdScroll');
  if(!rotEl||!canv)return;
  if(_brdIsPhonePortrait()){
    // Show overlay, hide canvas area, animate icon
    rotEl.style.display='flex';
    if(canv)canv.style.display='none';
    if(bgC)bgC.style.display='none';
    // Pulse animation on icon
    var ic=g('_brdRotIcon');
    if(ic){
      ic.style.transition='transform .6s cubic-bezier(.34,1.56,.64,1)';
      ic.style.transform='rotate(0deg)';
      setTimeout(function(){ic.style.transform='rotate(90deg)';
        setTimeout(function(){ic.style.transform='rotate(0deg)';},700);},100);
    }
  } else {
    // Landscape or tablet → hide overlay, re-init canvas with new dimensions
    rotEl.style.display='none';
    if(canv)canv.style.display='';
    if(bgC)bgC.style.display='';
    _boardInitCanvas();
  }
}

// Dessine une page (data URL JPEG) sur le canvas principal — async
function _boardRestorePage(dataUrl,cb){
  if(!_brdC||!_brdX){if(cb)cb();return;}
  var myEpoch=++_brdRestoreEpoch;
  _brdRestorePending=true;
  var img=new Image();
  img.onload=function(){
    if(_brdRestoreEpoch!==myEpoch){return;} // superseded by a newer navigation
    _brdRestorePending=false;
    _brdX.save();_brdX.setTransform(1,0,0,1,0,0);
    _brdX.clearRect(0,0,_brdC.width,_brdC.height);
    _brdX.drawImage(img,0,0,_brdC.width,_brdC.height); // scale to new dims après resize
    _brdX.restore();
    if(cb)cb();
  };
  img.onerror=function(){
    if(_brdRestoreEpoch!==myEpoch){return;}
    _brdRestorePending=false;
    if(cb)cb();
  };
  img.src=dataUrl;
}

function _boardInitCanvas(){
  var canv=g('_vBoardCanvas');if(!canv)return;
  var scroll=g('_brdScroll');if(!scroll)return;
  var page=g('_brdPage');
  // Register orientation listener FIRST (before portrait check, so rotating from portrait works)
  if(!_brdOrientHandler){
    _brdOrientHandler=function(){setTimeout(_brdCheckOrientation,120);};
    window.addEventListener('resize',_brdOrientHandler);
  }
  // Show rotate prompt instead if phone portrait
  if(_brdIsPhonePortrait()){_brdCheckOrientation();return;}
  var dpr=window.devicePixelRatio||1;
  var sw=scroll.clientWidth||window.innerWidth;
  var sh=scroll.clientHeight||(window.innerHeight-180);
  // Phone (landscape) → fill the full available area; tablet/desktop → 4:3 with margin
  var isPhone=Math.min(screen.width,screen.height)<500;
  var pw,ph;
  if(isPhone){
    var m=6;pw=Math.max(sw-m*2,180);ph=Math.max(sh-m*2,100);
  }else{
    var margin=32;
    pw=Math.min(sw-margin*2,(sh-margin*2)*(4/3));
    pw=Math.max(pw,180);ph=Math.round(pw*(3/4));pw=Math.round(pw);
  }
  if(page){page.style.width=pw+'px';page.style.height=ph+'px';}
  // Save current page strokes BEFORE clearing the canvas (prevents content loss on resize/orientation change)
  if(_brdC&&!_brdRestorePending)_boardSavePage();
  // Foreground canvas (strokes) — reset epoch so any pending restore from previous init is discarded
  _brdRestoreEpoch++;_brdRestorePending=false;
  canv.width=Math.round(pw*dpr);canv.height=Math.round(ph*dpr);
  canv.style.width=pw+'px';canv.style.height=ph+'px';
  _brdC=canv;_brdX=canv.getContext('2d');
  _brdX.scale(dpr,dpr);
  // Background canvas (grid — never erased)
  var bgC=g('_vBoardBg');
  if(bgC){bgC.width=Math.round(pw*dpr);bgC.height=Math.round(ph*dpr);bgC.style.width=pw+'px';bgC.style.height=ph+'px';_brdBgC=bgC;_brdBgX=bgC.getContext('2d');_brdBgX.scale(dpr,dpr);}
  _boardDrawBg();
  // Reset zoom/pan
  _brdZoom=1;_brdPanX=0;_brdPanY=0;_brdPinchInitDist=0;
  var _initDone=function(){
    if(!_brdHist.length){_brdHist=[{idx:0,data:_brdPages[0]||null}];_brdHistIdx=0;}
    _boardAttachEvents(canv);
    _boardUpdatePageTabs();
    _boardRenderSubbar();
  };
  if(_brdPages[_brdPageIdx]){
    _boardRestorePage(_brdPages[_brdPageIdx],_initDone);
  }else{
    _initDone();
  }
}

function _boardDrawBg(){
  // Draw white (+ optional grid) on the BACKGROUND canvas (so eraser never touches it)
  if(!_brdBgX||!_brdBgC)return;
  var w=parseInt(_brdBgC.style.width)||(_brdBgC.width/(window.devicePixelRatio||1));
  var h=parseInt(_brdBgC.style.height)||(_brdBgC.height/(window.devicePixelRatio||1));
  _brdBgX.fillStyle='#ffffff';_brdBgX.fillRect(0,0,w,h);
  if(_brdBgType!=='blank'){
    var step=24;_brdBgX.strokeStyle='rgba(0,0,0,0.055)';_brdBgX.lineWidth=0.6;
    for(var x=step;x<w;x+=step){_brdBgX.beginPath();_brdBgX.moveTo(x,0);_brdBgX.lineTo(x,h);_brdBgX.stroke();}
    for(var y=step;y<h;y+=step){_brdBgX.beginPath();_brdBgX.moveTo(0,y);_brdBgX.lineTo(w,y);_brdBgX.stroke();}
  }
}
function _boardToggleBg(){
  _brdBgType=_brdBgType==='grid'?'blank':'grid';
  _boardDrawBg();
  var btn=g('_brdBgBtn');if(btn)btn.style.opacity=_brdBgType==='grid'?'1':'0.45';
  if(_brdRoomId&&_brdCanEdit)_brdEmitOp({type:'bg',bgType:_brdBgType,pageIdx:_brdPageIdx});
  haptic(1);
}


function _brdEmitGotoPage(idx){
  if(!_brdRoomId||!_brdCanEdit)return;
  if(typeof _socket==='undefined'||!_socket||!_socket.connected)return;
  _socket.emit('board_goto_page',{roomId:_brdRoomId,pageIdx:idx});
  haptic(1);
  toast('Page synchronisée','Les élèves voient maintenant cette page',1600);
}

// ── Sync forcé (contenu + page) vers tous les élèves ────────────────────────
function _boardForceSyncAll(){
  if(!_brdRoomId||!_isOwner)return;
  if(typeof _socket==='undefined'||!_socket||!_socket.connected){toast('Non connecté','',1400);return;}
  _boardSavePage();
  var tmp=document.createElement('canvas');
  tmp.width=_brdC.width;tmp.height=_brdC.height;
  var tX=tmp.getContext('2d');
  tX.fillStyle='#ffffff';tX.fillRect(0,0,tmp.width,tmp.height);
  if(_brdBgC)tX.drawImage(_brdBgC,0,0);
  tX.drawImage(_brdC,0,0);
  var snap=tmp.toDataURL('image/jpeg',0.72);
  var allPages=_brdPages.map(function(p,i){return i===_brdPageIdx?snap:(p||null);});
  _socket.emit('board_force_sync',{
    roomId:_brdRoomId,snapshot:snap,allPages:allPages,
    pageIdx:_brdPageIdx,pageNames:_brdPageNames.slice(),
    pageCount:_brdPages.length,bgType:_brdBgType
  });
  // Animate sync button
  var btn=document.getElementById('_brdSyncBtn');
  if(btn){
    btn.style.transition='transform .55s cubic-bezier(.34,1.56,.64,1)';
    btn.style.transform='rotate(360deg)';
    setTimeout(function(){var b=document.getElementById('_brdSyncBtn');if(b){b.style.transition='none';b.style.transform='';}},600);
  }
  haptic(2);toast('Tableau synchronisé','Tous les élèves voient maintenant cette page',1800);
}

// ── Réception d'un sync forcé (côté élève) ───────────────────────────��──────
function _brdOnForceSyncReceived(data){
  if(_isOwner)return;
  _brdOnSync(data);
  setTimeout(_brdShowSyncRipple,180);
  toast('Tableau synchronisé par le prof','',1500);
}

// ── Ripple animation au centre du tableau ────────────────────────────────────
function _brdShowSyncRipple(){
  var page=g('_brdPage');if(!page)return;
  if(!document.getElementById('_syncRippleKf')){
    var s=document.createElement('style');s.id='_syncRippleKf';
    s.textContent='@keyframes _syncRipple{0%{transform:scale(0);opacity:.65}100%{transform:scale(3.8);opacity:0}}';
    document.head.appendChild(s);
  }
  var ov=document.createElement('div');
  ov.style.cssText='position:absolute;inset:0;pointer-events:none;z-index:20;overflow:hidden;display:flex;align-items:center;justify-content:center;';
  [0,220,440].forEach(function(delay){
    var ring=document.createElement('div');
    ring.style.cssText='position:absolute;width:28%;padding-bottom:28%;border-radius:50%;border:3px solid #FF6B2B;animation:_syncRipple 900ms '+delay+'ms ease-out both;opacity:0;';
    ov.appendChild(ring);
  });
  page.appendChild(ov);
  setTimeout(function(){if(ov.parentNode)ov.parentNode.removeChild(ov);},1700);
}

function _brdOnRemoteGotoPage(data){
  if(!data||typeof data.pageIdx!=='number')return;
  if(!_boardActive||_isOwner)return; // le prof ne se déplace pas lui-même
  if(data.pageIdx===_brdPageIdx)return;
  _boardGoPage(data.pageIdx);
}
// ── Snapshot helpers (canvas offscreen — GPU, pas de copie CPU getImageData) ──
function _brdMakeSnap(){
  if(!_brdC)return null;
  var tmp=document.createElement('canvas');
  tmp.width=_brdC.width;tmp.height=_brdC.height;
  tmp.getContext('2d').drawImage(_brdC,0,0);
  return tmp;
}
function _brdRestoreSnap(snap){
  if(!snap||!_brdX||!_brdC)return;
  _brdX.save();_brdX.setTransform(1,0,0,1,0,0);
  _brdX.clearRect(0,0,_brdC.width,_brdC.height);
  _brdX.drawImage(snap,0,0);
  _brdX.restore();
}
// ── Curseur gomme ──────────────────────────────────────────────────────────
function _brdShowEraserCursor(x,y){
  var page=g('_brdPage');if(!page)return;
  // Guard: after a page switch _brdPage is recreated — orphaned element must be replaced
  if(_brdEraserCursorEl&&_brdEraserCursorEl.parentNode!==page)_brdCleanEraserCursor();
  if(!_brdEraserCursorEl){
    _brdEraserCursorEl=document.createElement('div');
    _brdEraserCursorEl.style.cssText='position:absolute;border-radius:50%;border:1.5px solid rgba(80,80,80,.75);pointer-events:none;z-index:55;transform:translate(-50%,-50%);box-shadow:0 0 0 1px rgba(255,255,255,.4);transition:width .05s,height .05s;';
    page.appendChild(_brdEraserCursorEl);
  }
  // Masquer le curseur CSS pour éviter le double curseur (cercle + crosshair)
  if(_brdC)_brdC.style.cursor='none';
  // Pas de * _brdZoom : l'élément est dans _brdPage déjà CSS-transformé scale(zoom)
  _brdEraserCursorEl.style.width=_brdEr+'px';_brdEraserCursorEl.style.height=_brdEr+'px';
  _brdEraserCursorEl.style.left=x+'px';_brdEraserCursorEl.style.top=y+'px';
  _brdEraserCursorEl.style.display='block';
}
function _brdHideEraserCursor(){
  if(_brdEraserCursorEl)_brdEraserCursorEl.style.display='none';
  if(_brdC&&!_brdDraw)_brdC.style.cursor='crosshair';
}
function _brdCleanEraserCursor(){
  if(_brdEraserCursorEl&&_brdEraserCursorEl.parentNode)_brdEraserCursorEl.parentNode.removeChild(_brdEraserCursorEl);
  _brdEraserCursorEl=null;
}
function _boardClearFg(){
  if(!_brdX||!_brdC)return;
  _brdX.save();_brdX.setTransform(1,0,0,1,0,0);
  _brdX.clearRect(0,0,_brdC.width,_brdC.height);
  _brdX.restore();
  _brdObjects=[];
}
var _brdPanHideTimer=null;
function _boardApplyTransform(){
  var page=g('_brdPage');if(!page)return;
  // Pan limits: keep at least 60px of the canvas visible on each side
  var scroll=g('_brdScroll');
  if(scroll){
    var sw=scroll.clientWidth,sh=scroll.clientHeight;
    var pw=parseFloat(page.style.width)||800,ph=parseFloat(page.style.height)||600;
    var mx=sw/2+pw*_brdZoom/2-60,my=sh/2+ph*_brdZoom/2-60;
    _brdPanX=Math.max(-mx,Math.min(mx,_brdPanX));
    _brdPanY=Math.max(-my,Math.min(my,_brdPanY));
  }
  page.style.transformOrigin='center center';
  page.style.transform='translate('+_brdPanX+'px,'+_brdPanY+'px) scale('+_brdZoom+')';
  // Hide sub-toolbar + text editor while panning/zooming; restore after gesture ends
  var sub=g('_brdSub');if(sub)sub.style.opacity='0';
  var txtInp=g('_brdActiveInp');if(txtInp)txtInp.style.opacity='0';
  var txtWrap=g('_brdTxtWrap');if(txtWrap)txtWrap.style.opacity='0';
  var txtBar=g('_brdTxtBar');if(txtBar)txtBar.style.opacity='0';
  if(_brdPanHideTimer)clearTimeout(_brdPanHideTimer);
  _brdPanHideTimer=setTimeout(function(){
    var sub=g('_brdSub');if(sub)sub.style.opacity='';
    var bar=g('_brdTxtBar');if(bar)bar.style.opacity='';
    // Reposition textarea to match canvas after pan/zoom
    var inp=g('_brdActiveInp');
    var wrapEl=g('_brdTxtWrap');
    if((inp||wrapEl)&&_brdC&&_brdTextAnchor){
      var r=_brdC.getBoundingClientRect();
      var nx=(r.left+_brdTextAnchor.cx*_brdZoom)+'px',ny=(r.top+_brdTextAnchor.cy*_brdZoom)+'px';
      if(wrapEl){wrapEl.style.left=nx;wrapEl.style.top=ny;wrapEl.style.opacity='';}
      if(inp)inp.style.opacity='';
      if(bar){
        var ib=inp.getBoundingClientRect();
        var bw=bar.offsetWidth||220;
        var bl=Math.min(Math.max(ib.left,8),window.innerWidth-bw-8);
        var vvb=window.visualViewport?(window.visualViewport.offsetTop+window.visualViewport.height):window.innerHeight;
        var bt=ib.bottom+8;if(bt+38>vvb-8)bt=Math.max(8,vvb-48);
        bar.style.left=bl+'px';bar.style.top=bt+'px';
      }
    }else if(inp){inp.style.opacity='';}
    // Resync handles rotation/resize après zoom ou pan
    if(typeof _brdUpdateObjSelHandlePos==='function') _brdUpdateObjSelHandlePos();
  },320);
}

function _boardSaveHist(){
  if(!_brdC)return;
  if(_brdHistIdx<_brdHist.length-1)_brdHist.splice(_brdHistIdx+1);
  var tmp=document.createElement('canvas');
  tmp.width=_brdC.width;tmp.height=_brdC.height;
  tmp.getContext('2d').drawImage(_brdC,0,0);
  // JPEG 0.65 au lieu de PNG → 8x moins lourd en RAM (500KB → 60KB par entrée)
  var d=tmp.toDataURL('image/jpeg',0.65);
  // Épurer les objets image (base64 dans _brdImgStore, pas dans l'historique)
  var objSnap=JSON.parse(JSON.stringify(_brdObjects));
  objSnap.forEach(function(o){if(o.type==='image')delete o.data;});
  _brdHist.push({idx:_brdPageIdx,data:d,objects:objSnap});
  if(_brdHist.length>10)_brdHist.shift();else _brdHistIdx++; // 10 niveaux suffisent
}
function _boardUndo(){
  if(_brdHistIdx<=0||!_brdX)return;
  _brdCleanObjSel();
  _brdHistIdx--;
  var st=_brdHist[_brdHistIdx];_brdPageIdx=st.idx;
  if(st.objects)_brdObjects=JSON.parse(JSON.stringify(st.objects));
  _boardRestorePage(st.data,function(){
    _boardUpdatePageLabel();
    // Broadcast snapshot after undo so remote users converge to same state
    if(_brdRoomId&&_brdCanEdit&&_brdC){
      _boardSavePage();
      var snap=_brdPages[_brdPageIdx];
      if(snap)_brdEmitOp({type:'snapshot',data:snap});
    }
  });
  haptic(1);
}
function _boardRedo(){
  if(_brdHistIdx>=_brdHist.length-1||!_brdX)return;
  _brdCleanObjSel();
  _brdHistIdx++;
  var st=_brdHist[_brdHistIdx];_brdPageIdx=st.idx;
  if(st.objects)_brdObjects=JSON.parse(JSON.stringify(st.objects));
  _boardRestorePage(st.data,function(){_boardUpdatePageLabel();});
  haptic(1);
}
function _boardUpdatePageLabel(){_boardUpdatePageTabs();}
function _boardUpdatePageTabs(){
  var tabs=g('_brdTabs');if(!tabs)return;
  var h='';
  // Chrome-style: tabs ont une largeur min fixe, la barre scroll si besoin
  for(var i=0;i<_brdPages.length;i++){
    var a=i===_brdPageIdx;
    var label=escH((_brdPageNames[i]&&_brdPageNames[i].trim())||'Page '+(i+1));
    // Tab actif : fond blanc + boutons ; tab inactif : semi-transparent + pas de boutons
    var tabStyle='flex:1;min-width:'+(a?'72':'40')+'px;overflow:hidden;';
    h+='<button onclick="_boardGoPage('+i+')" style="'
      +tabStyle
      +'background:'+(a?'rgba(255,255,255,.92)':'rgba(255,255,255,.14)')+';'
      +'color:'+(a?'#222':'rgba(255,255,255,.72)')+';'
      +'border:none;cursor:pointer;font-family:inherit;font-size:11px;font-weight:'+(a?'600':'400')+';'
      +'padding:4px 6px 5px 8px;height:28px;border-radius:6px 6px 0 0;'
      +'display:flex;align-items:center;gap:4px;'
      +'-webkit-tap-highlight-color:transparent;">'
      +'<span style="flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">'+label+'</span>'
      +(_isOwner&&a?'<button onclick="event.stopPropagation();_boardRenamePage('+i+')" style="background:none;border:none;cursor:pointer;opacity:.55;font-size:11px;flex-shrink:0;padding:3px 3px;min-width:22px;min-height:22px;display:flex;align-items:center;justify-content:center;-webkit-tap-highlight-color:transparent;border-radius:4px;">✏️</button>':'')
      +(_isOwner&&a&&_brdPages.length>1?'<button onclick="event.stopPropagation();_boardDeletePage('+i+')" style="background:none;border:none;cursor:pointer;opacity:.6;font-size:17px;line-height:1;font-weight:300;flex-shrink:0;padding:3px 3px;min-width:22px;min-height:22px;display:flex;align-items:center;justify-content:center;-webkit-tap-highlight-color:transparent;border-radius:4px;">×</button>':'')
      +'</button>';
  }
  tabs.innerHTML=h;
  var at=tabs.children[_brdPageIdx];
  if(at)at.scrollIntoView({inline:'nearest',behavior:'smooth'});
}
function _boardDeletePage(idx){
  if(_brdPages.length<=1)return;
  _brdCleanObjSel();
  _brdPages.splice(idx,1);_brdPageNames.splice(idx,1);_brdPageHists.splice(idx,1);_brdObjPages.splice(idx,1);
  if(_brdPageIdx>=_brdPages.length)_brdPageIdx=_brdPages.length-1;
  _brdObjects=_brdObjPages[_brdPageIdx]?JSON.parse(JSON.stringify(_brdObjPages[_brdPageIdx])):[];
  var _dph=_brdPageHists[_brdPageIdx];
  if(_dph){_brdHist=_dph.hist.slice();_brdHistIdx=_dph.idx;}
  else{_brdHist=[];_brdHistIdx=-1;_boardSaveHist();}
  if(_brdPages[_brdPageIdx]){
    _boardRestorePage(_brdPages[_brdPageIdx],function(){_boardUpdatePageTabs();});
  }else{
    _boardClearFg();_boardUpdatePageTabs();
  }
  haptic(1);
  _brdEmitPageDelete(idx);
}
function _boardRenamePage(idx){
  // Inline rename : remplace le label de l'onglet par un <input> sans bloquer le thread
  var tabs=g('_brdTabs');if(!tabs)return;
  var tab=tabs.children[idx];if(!tab)return;
  var span=tab.querySelector('span');if(!span)return;
  var cur=(_brdPageNames[idx]&&_brdPageNames[idx].trim())||('Page '+(idx+1));
  var inp=document.createElement('input');
  inp.type='text';inp.value=cur;inp.maxLength=24;
  inp.style.cssText='width:100%;background:transparent;border:none;border-bottom:1.5px solid #FF6B2B;outline:none;color:inherit;font-family:inherit;font-size:inherit;font-weight:inherit;padding:0;min-width:0;';
  span.innerHTML='';span.appendChild(inp);
  inp.focus();inp.select();
  function _commit(){
    var name=(inp.value||'').trim()||cur;
    _brdPageNames[idx]=name;
    _boardUpdatePageTabs();haptic(1);
    _brdEmitPageRename(idx,name);
  }
  inp.addEventListener('blur',_commit,{once:true});
  inp.addEventListener('keydown',function(e){
    if(e.key==='Enter'){e.preventDefault();inp.blur();}
    else if(e.key==='Escape'){inp.value=cur;inp.blur();}
  });
}
function _boardGoPage(idx){
  if(idx===_brdPageIdx||!_brdX||_brdRestorePending)return;
  _brdClearConfirmT=0;
  if(_brdSel.active)_brdCommitSel();
  _brdCleanObjSel();
  var _sr=document.getElementById('_brdSnapRing');
  if(_sr){_sr.style.opacity='0';_sr.style.transform='translate(-50%,-50%) scale(0)';}
  if(!_brdRestorePending)_boardSavePage();
  // Sauvegarder objets + hist de la page courante
  _brdObjPages[_brdPageIdx]=JSON.parse(JSON.stringify(_brdObjects));
  _brdPageHists[_brdPageIdx]={hist:_brdHist.slice(),idx:_brdHistIdx};
  _brdPageIdx=idx;
  // Restaurer objets de la page destination
  _brdObjects=_brdObjPages[idx]?JSON.parse(JSON.stringify(_brdObjPages[idx])):[];
  if(_brdPages[_brdPageIdx]){
    _boardRestorePage(_brdPages[_brdPageIdx],function(){
      var saved=_brdPageHists[_brdPageIdx];
      if(saved){_brdHist=saved.hist.slice();_brdHistIdx=saved.idx;}
      else{_brdHist=[];_brdHistIdx=-1;_boardSaveHist();}
      _boardUpdatePageTabs();
    });
  }else{
    _brdRestorePending=false;_boardClearFg();
    _brdObjects=_brdObjPages[idx]?JSON.parse(JSON.stringify(_brdObjPages[idx])):[];
    // Si des objets ont été accumulés depuis d'autres utilisateurs (sans snapshot), les rendre
    if(_brdObjects.length>0){_brdRenderAll();_boardSavePage();}
    var saved=_brdPageHists[_brdPageIdx];
    if(saved){_brdHist=saved.hist.slice();_brdHistIdx=saved.idx;}
    else{_brdHist=[];_brdHistIdx=-1;_boardSaveHist();}
    _boardUpdatePageTabs();
  }
  haptic(1);
}
function _boardSavePage(){
  if(!_brdC||!_brdX)return;
  // Composite fond blanc + grille + traits avant de sauvegarder en JPEG.
  // JPEG ne supporte pas la transparence (transparent → noir) — sans cette composition
  // le canvas devient tout noir à chaque redimensionnement ou navigation de page.
  var tmp=document.createElement('canvas');
  tmp.width=_brdC.width;tmp.height=_brdC.height;
  var tctx=tmp.getContext('2d');
  tctx.fillStyle='#ffffff';tctx.fillRect(0,0,tmp.width,tmp.height);
  if(_brdBgC)tctx.drawImage(_brdBgC,0,0); // grille
  tctx.drawImage(_brdC,0,0); // traits
  _brdPages[_brdPageIdx]=tmp.toDataURL('image/jpeg',0.72);
}
function _boardAddPage(){
  if(_brdSel.active)_brdCommitSel();
  _brdCleanObjSel();
  if(!_brdRestorePending)_boardSavePage();
  _brdObjPages[_brdPageIdx]=JSON.parse(JSON.stringify(_brdObjects));
  _brdPageHists[_brdPageIdx]={hist:_brdHist.slice(),idx:_brdHistIdx};
  _brdPages.push(null);_brdPageNames.push('');_brdObjPages.push([]);
  _brdPageIdx=_brdPages.length-1;_brdObjects=[];
  _brdRestorePending=false;_boardClearFg();_brdHist=[];_brdHistIdx=-1;_boardSaveHist();_boardUpdatePageTabs();haptic(1);
  _brdEmitPageAdd();
}
function _boardPrevPage(){if(_brdPageIdx>0)_boardGoPage(_brdPageIdx-1);}
function _boardNextPage(){if(_brdPageIdx<_brdPages.length-1)_boardGoPage(_brdPageIdx+1);}

// ── New toolbar & popup system ──
function _boardUpdateToolbar(){_boardRenderSubbar();}
function _brdToolPD(tool){
  _brdLPFired=false;
  _brdLPTimer=setTimeout(function(){
    _brdLPFired=true;
    clearTimeout(_brdLPTimer);_brdLPTimer=null;
    if(_brdPinnedTool===tool){_brdPinnedTool=null;}
    else{_brdPinnedTool=tool;_brdTool=tool;if(_brdC)_brdC.style.cursor=tool==='text'?'text':tool==='hand'?'grab':'crosshair';}
    haptic(2);_boardRenderSubbar();
  },480);
}
function _brdToolPU(){if(_brdLPTimer){clearTimeout(_brdLPTimer);_brdLPTimer=null;}}
function _boardToolTap(tool){
  if(_brdLPFired){_brdLPFired=false;return;} // long-press géré, ignorer le click
  if(_brdPinnedTool&&_brdPinnedTool!==tool)return; // outil épinglé : blocage
  if(_brdSel.active)_brdCommitSel();
  if(_brdObjSel.active&&tool!=='select')_brdCleanObjSel();
  if(_brdTool==='laser'&&tool!=='laser')_brdHideLaserDot();
  _brdTool=tool;
  if(_brdC)_brdC.style.cursor=tool==='text'?'text':tool==='hand'?'grab':tool==='laser'?'none':'crosshair';
  _boardRenderSubbar();haptic(1);
}
function _boardSetTool(tool){_boardToolTap(tool);}
function _boardSetColor(c){_brdColor=c;_boardRenderSubbar();}
function _boardSetSize(sz){_brdSz=sz;_boardRenderSubbar();}
function _boardSetEraserSz(sz){
  _brdEr=sz;
  if(_brdEraserCursorEl&&_brdEraserCursorEl.style.display!=='none'){
    _brdEraserCursorEl.style.width=sz+'px';_brdEraserCursorEl.style.height=sz+'px';
  }
  _boardRenderSubbar();
}
function _boardSetShape(t){_brdShType=t;_boardRenderSubbar();}
function _boardToggleShFill(){_brdShFill=!_brdShFill;_boardRenderSubbar();}

// ── Insertion d'image — canvas only, zéro stockage serveur ──────────────────
function _boardInsertImageBtn(){
  if(_brdRoomId&&!_brdCanEdit){toast('Lecture seule','',1200);return;}
  var inp=document.createElement('input');
  inp.type='file';inp.accept='image/*';
  inp.onchange=function(){
    var file=inp.files&&inp.files[0];
    if(!file)return;
    if(file.size>5*1024*1024){toast('Image trop lourde','Max 5 Mo — compressez-la d\'abord.',3000);return;}
    var reader=new FileReader();
    reader.onload=function(ev){_boardInsertImage(ev.target.result);};
    reader.readAsDataURL(file);
  };
  inp.click();
}
function _boardInsertImage(dataUrl){
  var img=new Image();
  img.onload=function(){
    // Comprimer via canvas offscreen : max 1200px, JPEG 72%
    var maxW=1200,maxH=900;
    var w=img.naturalWidth,h=img.naturalHeight;
    if(w>maxW){h=Math.round(h*maxW/w);w=maxW;}
    if(h>maxH){w=Math.round(w*maxH/h);h=maxH;}
    var oc=document.createElement('canvas');oc.width=w;oc.height=h;
    oc.getContext('2d').drawImage(img,0,0,w,h);
    var compressed=oc.toDataURL('image/jpeg',0.72);
    if(compressed.length>350_000)compressed=oc.toDataURL('image/jpeg',0.50);
    if(compressed.length>1_100_000){toast('Image trop grande après compression','Essayez une image plus petite.',3000);return;}
    // Centrer sur la page visible
    var page=g('_brdPage');var pr=page?page.getBoundingClientRect():{left:0,top:0,width:800,height:600};
    var cx=(window.innerWidth/2-pr.left)/_brdZoom;
    var cy=(window.innerHeight/2-pr.top)/_brdZoom;
    var iw=Math.min(w,600)/_brdZoom,ih=iw*(h/w);
    var imgId='img_'+Date.now();
    // Stocker le base64 dans le store permanent (pas dans l'objet → pas dans l'historique)
    if(!_brdImgStore)_brdImgStore={};
    _brdImgStore[imgId]=compressed;
    var op={type:'image',x:cx-iw/2,y:cy-ih/2,w:iw,h:ih,id:imgId};
    _brdObjects.push(op);
    _boardSaveHist();_brdRedraw();
    // Pour le partage temps réel : inclure data UNIQUEMENT dans l'émission socket
    if(_brdRoomId&&_brdCanEdit)_brdEmitOp({type:'objinsert',obj:Object.assign({},op,{data:compressed})});
    toast('Image insérée','');haptic(2);
  };
  img.src=dataUrl;
}

